# Tests: custom exceptions, inheritance, abstract classes, try/except/else/finally

class OverdraftError(Exception):
    message: str
    def __init__(self, message: str):
        self.message = message

class TransactionLimitError(RuntimeError):
    limit: float
    requested: float
    def __init__(self, limit: float, requested: float):
        self.limit = limit
        self.requested = requested

@abstract
class Transaction:
    amount: float
    description: str

    def __init__(self, amount: float, description: str):
        self.amount = amount
        self.description = description

    @abstract
    def process(self, balance: float) -> float: ...

class DepositTransaction(Transaction):
    @override
    def process(self, balance: float) -> float:
        new_balance = balance + self.amount
        print(f"Deposited: {self.amount}")
        return new_balance

class WithdrawalTransaction(Transaction):
    @override
    def process(self, balance: float) -> float:
        if self.amount > balance:
            raise OverdraftError(f"Cannot withdraw {self.amount}, balance is {balance}")
        new_balance = balance - self.amount
        print(f"Withdrew: {self.amount}")
        return new_balance

class TransferTransaction(Transaction):
    recipient: str

    def __init__(self, amount: float, description: str, recipient: str):
        super().__init__(amount, description)
        self.recipient = recipient

    @override
    def process(self, balance: float) -> float:
        if self.amount > 1000.0:
            raise TransactionLimitError(1000.0, self.amount)
        if self.amount > balance:
            raise OverdraftError(f"Insufficient funds for transfer")
        print(f"Transferred {self.amount} to {self.recipient}")
        return balance - self.amount

class TransactionProcessor:
    _log: list[str]

    def __init__(self):
        self._log = []

    def execute(self, txn: Transaction, balance: float) -> float:
        result: float = balance
        self._log.append(f"Starting: {txn.description}")

        try:
            try:
                result = txn.process(balance)
            except OverdraftError as e:
                print(f"Overdraft prevented: {e.message}")
                result = balance
            except TransactionLimitError as e:
                print(f"Limit exceeded: requested {e.requested}, max {e.limit}")
                result = balance
            else:
                print("Transaction succeeded")
            finally:
                print("Processing complete")

        except Exception as e:
            print(f"Unexpected error: {type(e)}")
            result = balance
        finally:
            self._log.append(f"Completed: {txn.description}")

        return result

    def get_log_size(self) -> int:
        return len(self._log)

